+            response,
+            IoctlResult::Data(0xA5A5_1234_u32.to_ne_bytes().to_vec())
+        );
+        assert_eq!(
+            calls.lock().expect("lock ioctl calls").as_slice(),
+            &[
+                IoctlCall::Begin(RequestOp::IoctlRead),
+                IoctlCall::GetState(InodeNumber(29)),
+                IoctlCall::End(RequestOp::IoctlRead),
+            ]
